// Provider-agnostic: try all 4 AI agent sources
let aiItem = null;
const agents = ['AI Agent (Groq)', 'AI Agent (OpenAI)', 'AI Agent (Gemini)', 'AI Agent (Ollama)', 'Extract Groq Vision Output'];
for (const agentName of agents) {
  try {
    const items = $(agentName).all();
    if (items && items.length > 0) {
      aiItem = items[0].json;
      break;
    }
  } catch (e) { /* skip unavailable agent */ }
}
if (!aiItem) {
  try { aiItem = $input.first().json; } catch(e) { aiItem = {}; }
}

// Get original context (spreadsheetId, channel, userId, profileName, etc.)
let originalData = {};
try { originalData = $('Merge User Context').first().json; } catch(e) {}

// Extract the AI output text
const candidate = aiItem.output ?? aiItem.text ?? aiItem.response ?? aiItem.result ?? '';

// Try to parse JSON from the AI output
let parsed = null;
console.log(candidate, "<<<candidate")
if (typeof candidate === 'string') {
  console.log("masuk candidate string")
  const match = candidate.match(/(\[[\s\S]*\]|\{[\s\S]*\})/);
  if (match) {
  console.log("masuk match")
    try { parsed = JSON.parse(candidate.trim()); } catch(e) { parsed = null; console.log("error parsed", e)}
  }
  if (!parsed) {
  console.log("masuk !parsed")
    // Fallback: AI returned plain text instead of JSON
    parsed = { intent: 'help', replyText: candidate.trim() };
  }
} else if (typeof candidate === 'object' && candidate !== null) {
  console.log("masuk typeof candidate === 'object' && candidate !== null")
  parsed = candidate;
} else {
  console.log("<<<masuk else")
  parsed = { intent: 'help', replyText: String(candidate || 'No response from AI') };
}

// Ensure parsed is an object
if (!parsed || typeof parsed !== 'object') {
  console.log("masuk !parsed || typeof parsed !== 'object'")
  parsed = { intent: 'help', replyText: String(parsed || '') };
}

// Handle array response (e.g. multiple expenses from one receipt image)
if (Array.isArray(parsed)) {
  return parsed.map(item => {
    const parsedIntent = item.intent || 'help';
    const replyText = item.replyText || item.text || item.response || '';
    return { json: { ...originalData, ...item, parsedIntent, replyText } };
  });
}

const parsedIntent = parsed.intent || 'help';
const replyText = parsed.replyText || parsed.text || parsed.response || '';

// Merge original context + parsed AI output
// originalData carries: spreadsheetId, channel, userId, userName, profileName, messageText, etc.
// parsed carries: intent, amount, category, date, description, replyText, etc.
return [{
  json: {
    ...originalData,
    ...parsed,
    parsedIntent,
    replyText
  }
}];

const response = $input.first().json;
const sheets = (response.sheets || []).map(s => s.properties.title);
const now = new Date();
const monthNames = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
const monthSheet = monthNames[now.getMonth()] + '-' + now.getFullYear();
const allExpenses = $('Route by Intent').all();

return allExpenses.map(item => ({
  json: {
    ...item.json,
    monthSheet,
    sheetExists: sheets.includes(monthSheet),
    spreadsheetId: item.json.spreadsheetId
  }
}));

