const allExpenses = $('Check and Create Month Sheet').all();
const dashRows = $input.first().json.values || [];
const firstExpense = allExpenses[0].json;

// Aggregate total amount per category to avoid double-write on same dashboard row
const categoryTotals = {};
for (const item of allExpenses) {
  const exp = item.json;
  const cat = exp.category || 'Lain-lain';
  categoryTotals[cat] = (categoryTotals[cat] || 0) + (Number(exp.amount) || 0);
}

// One output item per unique category
return Object.entries(categoryTotals).map(([category, totalAmount]) => {
  let rowNumber = 9;
  let currentSpent = 0;
  let budget = 0;
  for (let i = 1; i < dashRows.length; i++) {
    if (dashRows[i][0] === category) {
      rowNumber = i + 1;
      budget = Number(dashRows[i][1]) || 0;
      currentSpent = Number(dashRows[i][2]) || 0;
      break;
    }
  }
  const newSpent = currentSpent + totalAmount;
  const remaining = budget - newSpent;
  return {
    json: {
      spreadsheetId: firstExpense.spreadsheetId,
      channel: firstExpense.channel,
      userId: firstExpense.userId,
      profileName: firstExpense.profileName,
      sessionId: firstExpense.sessionId,
      category,
      dashboardRow: rowNumber,
      newSpent,
      remaining
    }
  };
});

const allExpenses = $('Check and Create Month Sheet').all();
const firstExpense = allExpenses[0].json;
const totalAmount = allExpenses.reduce((sum, item) => sum + (Number(item.json.amount) || 0), 0);

const lines = ['✅ Expenses Recorded:'];
for (const item of allExpenses) {
  const exp = item.json;
  const amt = Number(exp.amount) || 0;
  lines.push('• ' + (exp.description || '-') + ': Rp ' + amt.toLocaleString('id-ID') + ' (' + (exp.category || 'Lain-lain') + ')');
}
if (allExpenses.length > 1) {
  lines.push('\nTotal: Rp ' + totalAmount.toLocaleString('id-ID'));
}

return [{
  json: {
    spreadsheetId: firstExpense.spreadsheetId,
    channel: firstExpense.channel,
    userId: firstExpense.userId,
    profileName: firstExpense.profileName,
    sessionId: firstExpense.sessionId,
    parsedIntent: 'record_expense',
    amount: totalAmount,
    category: allExpenses.length === 1 ? (allExpenses[0].json.category || 'Lain-lain') : 'multiple',
    replyText: lines.join('\n')
  }
}];

const apiResponse = $input.first().json;
const allRows = apiResponse.values || [];
const originalData = $('Route by Intent').first().json;
const category = originalData.category;

// allRows[0] = header, allRows[1..8] = data
// Columns: A=Category, B=Budget, C=Spent This Month, D=Remaining
let lines = ['📊 Budget Status:\n'];

for (let i = 1; i < allRows.length; i++) {
  const row = allRows[i];
  const cat = row[0] || '';
  if (category && cat !== category) continue;
  const budget = Number(row[1]) || 0;
  const spent = Number(row[2]) || 0;
  const remaining = budget - spent;
  const status = budget > 0 ? (remaining >= 0 ? '✅' : '⚠️') : '—';
  lines.push(`${status} ${cat}: Spent ${spent.toLocaleString()} / Budget ${budget.toLocaleString()} (Remaining: ${remaining.toLocaleString()})`);
}

return [{
  json: {
    ...originalData,
    replyText: lines.join('\n')
  }
}];

const data = $input.first().json;
const categories = ['Makanan & Minuman', 'Transportasi', 'Tagihan', 'Hiburan', 'Belanja', 'Kesehatan', 'Langganan', 'Lain-lain'];
const idx = categories.indexOf(data.category);
const budgetRow = idx >= 0 ? idx + 2 : 9; // row 2-9, default to Lain-lain (row 9)

return [{
  json: {
    ...data,
    budgetRow
  }
}];

const data = $input.first().json;
const originalData = $('Route by Intent').first().json;
return [{
  json: {
    ...originalData,
    replyText: `✅ Budget set: ${originalData.category} = ${originalData.currency || 'IDR'} ${Number(originalData.amount).toLocaleString()} per ${originalData.period || 'month'}`
  }
}];

const apiResponse = $input.first().json;
const allRows = apiResponse.values || [];
const originalData = $('Route by Intent').first().json;

// allRows[0] = header [Date, Description, Category, Amount, ...]
// allRows[1..n] = data rows
const byCategory = {};
let total = 0;
let txCount = 0;

for (let i = 1; i < allRows.length; i++) {
  const row = allRows[i];
  const cat = row[2] || 'Lain-lain'; // Column C = Category
  const amt = Number(row[3]) || 0;    // Column D = Amount
  byCategory[cat] = (byCategory[cat] || 0) + amt;
  total += amt;
  txCount++;
}

let lines = [`📊 Expense Report (${originalData.period || 'This Month'}):\n`];
const sorted = Object.entries(byCategory).sort((a, b) => b[1] - a[1]);

for (const [cat, amt] of sorted) {
  const pct = total > 0 ? ((amt / total) * 100).toFixed(1) : 0;
  lines.push(`• ${cat}: IDR ${amt.toLocaleString()} (${pct}%)`);
}

if (txCount === 0) {
  lines.push('No expenses recorded this period.');
}

lines.push(`\n💰 Total: IDR ${total.toLocaleString()}`);
lines.push(`📝 Transactions: ${txCount}`);

return [{
  json: {
    ...originalData,
    replyText: lines.join('\n')
  }
}];

const data = $input.first().json;
const splitWith = data.splitWith;
